+  [AgentEvents.AGENTS_COMPLETED]: AgentsCompletedPayload;
+  [AgentEvents.AGENTS_FAILED]: AgentsFailedPayload;
+  [AgentEvents.AGENTS_JOINED]: AgentsJoinedPayload;
+}

