+  if (agents.length === 0) {
+    const parts = [
+      `No agents found for scope=${scope}.`,
+      "Expected locations:",
+      "- ~/.pi/agents/*.md",
+      "- nearest .pi/agents/*.md",
+    ];
+    if (diagnostics.length > 0) {
+      parts.push("", "Diagnostics:", ...diagnostics.map((d) => `- ${d}`));
+    }
+    return parts.join("\n");
+  }
