+function createSpawnProcess(
+  handler: (input: string) => string,
+  inputs: string[],
+): SpawnProcess {
+  return (_command, _args, _options) => {
+    const stdout = new PassThrough();
+    const stderr = new PassThrough();
+    let capturedInput = "";
+    const stdin = new Writable({
+      write(chunk, _encoding, callback) {
+        capturedInput += chunk.toString();
+        callback();
+      },
+      final(callback) {
+        inputs.push(capturedInput);
+        const event = {
+          type: "message_end",
+          message: {
+            role: "assistant",
+            content: [{ type: "text", text: handler(capturedInput) }],
+            usage: {
+              input: 1,
+              output: 1,
+              totalTokens: 2,
+              cost: { total: 0 },
+            },
+          },
+        };
+        queueMicrotask(() => {
+          stdout.write(`${JSON.stringify(event)}\n`);
+          proc.emit("close", 0, null);
+        });
+        callback();
+      },
+    });
+    const proc =
+      new EventEmitter() as unknown as ChildProcessWithoutNullStreams;
+    Object.assign(proc, {
+      stdout,
+      stderr,
+      stdin,
+      exitCode: null,
+      signalCode: null,
+      kill() {
+        return true;
+      },
+    });
+    return proc;
+  };
+}
+
+async function waitFor(
+  predicate: () => boolean,
+  timeoutMs = 250,
+): Promise<void> {
+  const deadline = Date.now() + timeoutMs;
+  while (!predicate()) {
+    if (Date.now() >= deadline) {
+      throw new Error("Timed out waiting for background work.");
+    }
+    await new Promise((resolve) => setTimeout(resolve, 10));
+  }
+}
